// MARK: - Models

struct StockQuote: Codable, Identifiable, Hashable {
    let symbol: String
    let price: Double
    let change: Double
    let changePercent: Double
    let timestamp: Date
    
    var id: String { symbol }
}

enum TradeSide: String, Codable {
    case buy
    case sell
}

enum OrderType: String, Codable {
    case market
    case limit
}

enum TradeStatus: String, Codable {
    case pending
    case filled
    case rejected
    case cancelled
}

struct TradeOrder: Codable, Identifiable, Hashable {
    let id: UUID
    let symbol: String
    let side: TradeSide
    let orderType: OrderType
    let quantity: Int
    let limitPrice: Double?
    let createdAt: Date
    var status: TradeStatus
    var executedPrice: Double?
    var message: String?
}

struct Holding: Codable, Identifiable, Hashable {
    let symbol: String
    var quantity: Int
    var averageCost: Double
    var currentPrice: Double
    
    var id: String { symbol }
    var marketValue: Double { Double(quantity) * currentPrice }
    var costBasis: Double { Double(quantity) * averageCost }
    var unrealizedPnL: Double { marketValue - costBasis }
    var unrealizedPnLPercent: Double {
        guard costBasis != 0 else { return 0 }
        return (unrealizedPnL / costBasis) * 100
    }
}

struct PortfolioSummary: Codable, Hashable {
    var cashBalance: Double
    var holdings: [Holding]
    
    var totalMarketValue: Double {
        holdings.reduce(0) { $0 + $1.marketValue }
    }
    
    var totalEquity: Double {
        cashBalance + totalMarketValue
    }
    
    var totalUnrealizedPnL: Double {
        holdings.reduce(0) { $0 + $1.unrealizedPnL }
    }
}

