// MARK: - Secure Storage

final class SecureKeychain {
    static let shared = SecureKeychain()
    private init() {}
    
    func save(_ value: String, for key: String) throws {
        let data = Data(value.utf8)
        let query: [String: Any] = [
            kSecClass as String: kSecClassGenericPassword,
            kSecAttrAccount as String: key
        ]
        SecItemDelete(query as CFDictionary)
        let attributes: [String: Any] = [
            kSecClass as String: kSecClassGenericPassword,
            kSecAttrAccount as String: key,
            kSecValueData as String: data
        ]
        let status = SecItemAdd(attributes as CFDictionary, nil)
        guard status == errSecSuccess else { throw NSError(domain: "Keychain", code: Int(status)) }
    }
    
    func load(_ key: String) throws -> String {
        let query: [String: Any] = [
            kSecClass as String: kSecClassGenericPassword,
            kSecAttrAccount as String: key,
            kSecReturnData as String: true,
            kSecMatchLimit as String: kSecMatchLimitOne
        ]
        var result: CFTypeRef?
        let status = SecItemCopyMatching(query as CFDictionary, &result)
        guard status == errSecSuccess, let data = result as? Data, let value = String(data: data, encoding: .utf8) else {
            throw NSError(domain: "Keychain", code: Int(status))
        }
        return value
    }
    
    func delete(_ key: String) {
        let query: [String: Any] = [
            kSecClass as String: kSecClassGenericPassword,
            kSecAttrAccount as String: key
        ]
        SecItemDelete(query as CFDictionary)
    }
}

// MARK: - API Client

final class TradingAPIClient {
    static let shared = TradingAPIClient()
    
    private let baseURL: URL
    private let session: URLSession
    private let tokenKey = "trading_api_token"
    
    private init(baseURL: URL = URL(string: "https://api.example.com")!) {
        self.baseURL = baseURL
        let config = URLSessionConfiguration.default
        config.timeoutIntervalForRequest = 15
        config.timeoutIntervalForResource = 30
        config.waitsForConnectivity = true
        self.session = URLSession(configuration: config)
    }
    
    func setAuthToken(_ token: String) {
        try? SecureKeychain.shared.save(token, for: tokenKey)
    }
    
    private func authToken() -> String? {
        try? SecureKeychain.shared.load(tokenKey)
    }
    
    private func makeRequest(path: String, method: String, body: Data? = nil) -> URLRequest {
        var request = URLRequest(url: baseURL.appendingPathComponent(path))
        request.httpMethod = method
        request.httpBody = body
        request.setValue("application/json", forHTTPHeaderField: "Content-Type")
        request.setValue("application/json", forHTTPHeaderField: "Accept")
        if let token = authToken() {
            request.setValue("Bearer \(token)", forHTTPHeaderField: "Authorization")
        }
        return request
    }
    
    func fetchQuote(symbol: String) async throws -> StockQuote {
        let request = makeRequest(path: "quotes/\(symbol)", method: "GET")
        let (data, response) = try await session.data(for: request)
        try validate(response: response)
        let decoded = try JSONDecoder.api.decode(APIQuoteResponse.self, from: data)
        return StockQuote(symbol: decoded.symbol, price: decoded.price, change: decoded.change, changePercent: decoded.changePercent, timestamp: decoded.timestamp)
    }
    
    func executeTrade(_ order: TradeOrder) async throws -> TradeOrder {
        let payload = APITradeRequest(symbol: order.symbol, side: order.side, orderType: order.orderType, quantity: order.quantity, limitPrice: order.limitPrice)
        let body = try JSONEncoder.api.encode(payload)
        let request = makeRequest(path: "trades/execute", method: "POST", body: body)
        let (data, response) = try await session.data(for: request)
        try validate(response: response)
        let decoded = try JSONDecoder.api.decode(APITradeResponse.self, from: data)
        return TradeOrder(id: decoded.orderId, symbol: order.symbol, side: order.side, orderType: order.orderType, quantity: order.quantity, limitPrice: order.limitPrice, createdAt: order.createdAt, status: decoded.status, executedPrice: decoded.executedPrice, message: decoded.message)
    }
    
    func fetchPortfolio() async throws -> PortfolioSummary {
        let request = makeRequest(path: "portfolio", method: "GET")
        let (data, response) = try await session.data(for: request)
        try validate(response: response)
        return try JSONDecoder.api.decode(PortfolioSummary.self, from: data)
    }
    
    private func validate(response: URLResponse) throws {
        guard let http = response as? HTTPURLResponse else { throw URLError(.badServerResponse) }
        guard (200...299).contains(http.statusCode) else { throw NSError(domain: "API", code: http.statusCode) }
    }
}

