// MARK: - Market Data Service

@MainActor
final class MarketDataService: ObservableObject {
    @Published var quotes: [String: StockQuote] = [:]
    @Published var isConnected: Bool = false
    @Published var lastError: String?
    
    private var timer: AnyCancellable?
    private let symbols: [String]
    private let api = TradingAPIClient.shared
    
    init(symbols: [String]) {
        self.symbols = symbols
    }
    
    func start() {
        stop()
        isConnected = true
        timer = Timer.publish(every: 3, on: .main, in: .common)
            .autoconnect()
            .sink { [weak self] _ in
                guard let self else { return }
                Task {
                    await self.refreshQuotes()
                }
            }
    }
    
    func stop() {
        timer?.cancel()
        timer = nil
        isConnected = false
    }
    
    func refreshQuotes() async {
        do {
            try await withThrowingTaskGroup(of: StockQuote.self) { group in
                for symbol in symbols {
                    group.addTask {
                        try await self.api.fetchQuote(symbol: symbol)
                    }
                }
                var updated: [String: StockQuote] = [:]
                for try await quote in group {
                    updated[quote.symbol] = quote
                }
                self.quotes.merge(updated) { _, new in new }
                self.lastError = nil
            }
        } catch {
            lastError = error.localizedDescription
        }
    }
}

// MARK: - Portfolio ViewModel

@MainActor
final class PortfolioViewModel: ObservableObject {
    @Published var summary = PortfolioSummary(cashBalance: 0, holdings: [])
    @Published var orders: [TradeOrder] = []
    @Published var isLoading = false
    @Published var errorMessage: String?
    
    private let api = TradingAPIClient.shared
    
    func loadPortfolio() async {
        isLoading = true
        defer { isLoading = false }
        do {
            summary = try await api.fetchPortfolio()
            errorMessage = nil
        } catch {
            errorMessage = error.localizedDescription
        }
    }
    
    func submitOrder(symbol: String, side: TradeSide, orderType: OrderType, quantity: Int, limitPrice: Double?) async {
        let order = TradeOrder(id: UUID(), symbol: symbol, side: side, orderType: orderType, quantity: quantity, limitPrice: limitPrice, createdAt: Date(), status: .pending, executedPrice: nil, message: nil)
        orders.insert(order, at: 0)
        do {
            let executed = try await api.executeTrade(order)
            if let idx = orders.firstIndex(where: { $0.id == order.id }) {
                orders[idx] = executed
            }
            await loadPortfolio()
        } catch {
            if let idx = orders.firstIndex(where: { $0.id == order.id }) {
                orders[idx].status = .rejected
                orders[idx].message = error.localizedDescription
            }
            errorMessage = error.localizedDescription
        }
    }
}

// MARK: - Trading ViewModel

@MainActor
final class TradingViewModel: ObservableObject {
    @Published var symbol: String = "AAPL"
    @Published var quantity: String = "1"
    @Published var limitPrice: String = ""
    @Published var side: TradeSide = .buy
    @Published var orderType: OrderType = .market
    @Published var isSubmitting = false
    @Published var statusMessage: String?
    
    let portfolioVM: PortfolioViewModel
    
    init(portfolioVM: PortfolioViewModel) {
        self.portfolioVM = portfolioVM
    }
    
    func submit() async {
        guard let qty = Int(quantity), qty > 0 else {
            statusMessage = "Enter a valid quantity."
            return
        }
        let limit = Double(limitPrice)
        if orderType == .limit, limit == nil {
            statusMessage = "Enter a valid limit price."
            return
        }
        isSubmitting = true
        defer { isSubmitting = false }
        statusMessage = nil
        await portfolioVM.submitOrder(symbol: symbol.uppercased(), side: side, orderType: orderType, quantity: qty, limitPrice: limit)
        statusMessage = "Order submitted."
    }
}

